class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n
        self.components = n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])  # path compression
        return self.parent[x]

    def union(self, x, y):
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return False
        # Union by rank
        if self.rank[rx] < self.rank[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        if self.rank[rx] == self.rank[ry]:
            self.rank[rx] += 1
        self.components -= 1
        return True

    def connected(self, x, y):
        return self.find(x) == self.find(y)

import hashlib

class MerkleTree:
    def __init__(self, data_blocks):
        self.leaves = [self._hash(block) for block in data_blocks]
        if len(self.leaves) % 2 == 1:
            self.leaves.append(self.leaves[-1])  # duplicate last for even count
        self.root = self._build(self.leaves)

    @staticmethod
    def _hash(data):
        if isinstance(data, str):
            data = data.encode()
        return hashlib.sha256(data).hexdigest()

    def _build(self, nodes):
        if len(nodes) == 1:
            return nodes[0]
        next_level = []
        for i in range(0, len(nodes), 2):
            left = nodes[i]
            right = nodes[i + 1] if i + 1 < len(nodes) else nodes[i]
            combined = self._hash(left + right)
            next_level.append(combined)
        return self._build(next_level)

    def verify(self, data_blocks):
        other = MerkleTree(data_blocks)
        return self.root == other.root

import time
from collections import deque
import threading

class SlidingWindowLog:
    def __init__(self, max_requests, window_seconds):
        self.max_requests = max_requests
        self.window = window_seconds
        self.logs = {}  # key -> deque of timestamps
        self.lock = threading.Lock()

    def allow(self, key):
        now = time.time()
        with self.lock:
            if key not in self.logs:
                self.logs[key] = deque()

            log = self.logs[key]
            # Remove expired timestamps
            while log and log[0] <= now - self.window:
                log.popleft()

            if len(log) < self.max_requests:
                log.append(now)
                return True
            return False

    def remaining(self, key):
        now = time.time()
        with self.lock:
            log = self.logs.get(key, deque())
            while log and log[0] <= now - self.window:
                log.popleft()
            return max(0, self.max_requests - len(log))
